import threading

# Safe to share across threads — tuple is read-only
SPECIAL_TOKENS = ("[CLS]", "[SEP]", "[MASK]", "[PAD]", "[UNK]")

def worker(token_ids):
    for token_id in token_ids:
        # SPECIAL_TOKENS is safely accessible from any thread
        if SPECIAL_TOKENS[token_id % len(SPECIAL_TOKENS)]:
            pass

threads = [threading.Thread(target=worker, args=([i],)) for i in range(8)]
for t in threads:
    t.start()
for t in threads:
    t.join()
